// GetActiveVacancyListParams defines parameters for GetActiveVacancyList.
type GetActiveVacancyListParams struct {
	// Page Номер страницы (считается от 0)
	Page *float32 `form:"page,omitempty" json:"page,omitempty"`

	// PerPage Количество элементов
	PerPage *float32 `form:"per_page,omitempty" json:"per_page,omitempty"`

	// ManagerId Идентификатор менеджера, вакансии которого будут получены в ответе. По умолчанию возвращаются вакансии текущего пользователя.
	// Этот параметр нельзя передавать в комбинации с параметрами `manager_ids` и `all_accessible`.
	// Если передать несколько `manager_id`, будет использован последний. Значения можно взять из [списка](#tag/Menedzhery-rabotodatelya/operation/get-employer-managers)
	ManagerId *string `form:"manager_id,omitempty" json:"manager_id,omitempty"`

	// ManagerIds Идентификаторы менеджеров, вакансии которых будут получены в ответе. По умолчанию возвращаются вакансии текущего пользователя.
	// Этот параметр нельзя передавать в комбинации с параметрами `manager_id` и `all_accessible`.
	// Значения должны быть переданы строкой через запятую.
	// Значения можно взять из [списка](#tag/Menedzhery-rabotodatelya/operation/get-employer-managers)
	ManagerIds *string `form:"manager_ids,omitempty" json:"manager_ids,omitempty"`

	// Text Строка для поиска по названию вакансии
	Text *string `form:"text,omitempty" json:"text,omitempty"`

	// Area Идентификатор региона с вакансией. Чтобы получить идентификаторы регионов, в которых есть активные вакансии, воспользуйтесь [соответствующим методом](#tag/Informaciya-o-rabotodatele/operation/get-employer-vacancy-areas)
	Area *string `form:"area,omitempty" json:"area,omitempty"`

	// AllAccessible Позволяет получить все активные вакансии текущего пользователя вместе со всеми активными вакансиями менеджеров, к которым ему выдан доступ.
	// Этот параметр нельзя передавать в комбинации с параметрами `manager_id` и `manager_ids`
	AllAccessible *bool `form:"all_accessible,omitempty" json:"all_accessible,omitempty"`

	// DepartmentId Идентификатор департамента работодателя, от имени которого размещается вакансия (если данная возможность доступна для компании).
	// Значения можно взять из [списка](#tag/Informaciya-o-rabotodatele/operation/get-employer-departments)
	DepartmentId *string `form:"department_id,omitempty" json:"department_id,omitempty"`

	// ResumeId Идентификатор резюме. Этот параметр нельзя передавать в комбинации с другими параметрами, только отдельно. Если параметр передан, в ответе возвращаются только те вакансии, которые подходят для указанного резюме, а также дополнительные поля
	ResumeId *string `form:"resume_id,omitempty" json:"resume_id,omitempty"`

	// OrderBy Способ сортировки вакансий. Доступные значения перечислены в поле `employer_active_vacancies_order` в [справочнике полей](#tag/Obshie-spravochniki/operation/get-dictionaries)
	OrderBy *string `form:"order_by,omitempty" json:"order_by,omitempty"`

	// Host Доменное имя сайта (см. [Выбор сайта](#section/Obshaya-informaciya/Vybor-sajta))
	Host *GetActiveVacancyListParamsHost `form:"host,omitempty" json:"host,omitempty"`

	// Locale Идентификатор локали (см. [Локализация](#tag/Obshie-spravochniki/operation/get-locales))
	Locale *Locale `form:"locale,omitempty" json:"locale,omitempty"`

	// HHUserAgent Название приложения и контактная почта разработчика (см. [Информация о клиенте](#section/Obshaya-informaciya/Trebovaniya-k-zaprosam))
	HHUserAgent HHUserAgent `json:"HH-User-Agent"`
}

